# Template A skeleton — single-region SaaS
# All resources in one region; LLM via SaaS API

terraform {
  required_providers {
    aws = { source = "hashicorp/aws", version = "~> 5.0" }
  }
}

variable "region"  { default = "eu-west-1" }
variable "project" { default = "fnol-genai" }

provider "aws" { region = var.region }

# --- Application Layer ---
resource "aws_ecs_cluster" "app" {
  name = "${var.project}-cluster"
}

# --- Vector Store (Aurora PostgreSQL + pgvector) ---
resource "aws_rds_cluster" "vector_store" {
  cluster_identifier = "${var.project}-vectors"
  engine             = "aurora-postgresql"
  engine_version     = "15.4"
  database_name      = "embeddings"
  master_username    = "fnol_app"
  manage_master_user_password = true  # Secrets Manager rotation
}

# --- Secrets (LLM API keys) ---
resource "aws_secretsmanager_secret" "llm_key" {
  name                    = "${var.project}/openai-api-key"
  recovery_window_in_days = 7
}
